@startuml
abstract class DwarenMineWorker {
  goToSleep()
  wakeUp()
  goHome()
  goToMine()
  {abstract} String name()
  {abstract} void work()
}

class DwarenGoldmineFacade {
  Collection<DwarenMineWorker> worker
  - {static} makeAction(worker:Collection<DwarenMineWorker>,actions)
  + startNewDay()
  + digOutMine()
  + endDay()
}

